/**
 * Certificate PDF Download Utility
 * This utility requires html2canvas and jsPDF to be installed
 * Install with: npm install html2canvas jspdf
 */

export const downloadCertificateAsPDF = async (certificateRef, studentName, certificateId) => {
  try {
    // Dynamically import libraries (fallback if not installed)
    let html2canvas, jsPDF;

    try {
      html2canvas = (await import('html2canvas')).default;
      jsPDF = (await import('jspdf')).jsPDF;
    } catch (err) {
      console.error('Required libraries not installed. Please install: npm install html2canvas jspdf');
      alert('PDF export feature is not available. Please install required libraries.');
      return;
    }

    // Show loading state
    const originalText = 'Generating PDF...';
    const btn = document.activeElement;
    if (btn) btn.disabled = true;

    // Capture the certificate element as canvas
    const canvas = await html2canvas(certificateRef, {
      scale: 2,
      allowTaint: true,
      useCORS: true,
      backgroundColor: '#1e3c72',
      logging: false,
    });

    // Get dimensions
    const imgData = canvas.toDataURL('image/png');
    const imgWidth = 210; // A4 width in mm
    const imgHeight = (canvas.height * imgWidth) / canvas.width;

    // Create PDF
    const pdf = new jsPDF({
      orientation: imgHeight > imgWidth ? 'portrait' : 'landscape',
      unit: 'mm',
      format: 'a4',
    });

    const pageHeight = pdf.internal.pageSize.getHeight();
    const pageWidth = pdf.internal.pageSize.getWidth();

    // Calculate dimensions to fit page
    let finalWidth = pageWidth;
    let finalHeight = (canvas.height * finalWidth) / canvas.width;

    if (finalHeight > pageHeight) {
      finalHeight = pageHeight;
      finalWidth = (canvas.width * finalHeight) / canvas.height;
    }

    const xOffset = (pageWidth - finalWidth) / 2;
    const yOffset = (pageHeight - finalHeight) / 2;

    // Add image to PDF
    pdf.addImage(imgData, 'PNG', xOffset, yOffset, finalWidth, finalHeight);

    // Generate filename
    const filename = `Certificate_${studentName.replace(/\s+/g, '_')}_${certificateId.replace(/[^a-zA-Z0-9]/g, '_')}.pdf`;

    // Download PDF
    pdf.save(filename);

    if (btn) {
      btn.disabled = false;
    }

    return filename;
  } catch (error) {
    console.error('Error generating PDF:', error);
    alert('Error generating PDF. Please try again.');
    const btn = document.activeElement;
    if (btn) btn.disabled = false;
  }
};

/**
 * Alternative: Canvas-based PDF generation (lightweight, no external dependencies)
 * This creates a simpler PDF without the certificate template preview
 */
export const generateCertificatePDFSimple = (certificate) => {
  try {
    // Check if jsPDF is available
    const jsPDF = window.jspdf?.jsPDF;
    if (!jsPDF) {
      alert('PDF library not available. Please install jspdf: npm install jspdf');
      return;
    }

    const pdf = new jsPDF({
      orientation: 'landscape',
      unit: 'mm',
      format: 'a4',
    });

    const pageWidth = pdf.internal.pageSize.getWidth();
    const pageHeight = pdf.internal.pageSize.getHeight();
    const margin = 20;

    let yPosition = margin;
    const lineHeight = 7;
    const textWidth = pageWidth - 2 * margin;

    // Title
    pdf.setFontSize(32);
    pdf.setFont('courier', 'bold');
    pdf.text('CERTIFICATE', pageWidth / 2, yPosition, { align: 'center' });
    yPosition += lineHeight * 2;

    pdf.setFontSize(18);
    pdf.text('of Completion', pageWidth / 2, yPosition, { align: 'center' });
    yPosition += lineHeight * 2.5;

    // Content
    pdf.setFontSize(12);
    pdf.setFont('courier', 'normal');

    const contentLines = [
      ['This certificate is proudly presented to', 'center'],
      ['', ''],
      [certificate.studentName || 'Student Name', 'center', 'bold'],
      ['', ''],
      ['for successfully completing the course', 'center'],
      ['', ''],
      [certificate.courseName || 'Course Name', 'center', 'bold'],
      ['', ''],
      [`Grade Awarded: ${certificate.gradeAwarded || 'A'}`, 'center'],
      ['', ''],
      [`"${certificate.remarks || 'Outstanding Performance'}"`, 'center'],
    ];

    contentLines.forEach(([text, align = 'left', weight = 'normal']) => {
      if (!text) {
        yPosition += lineHeight;
        return;
      }

      if (weight === 'bold') {
        pdf.setFont('courier', 'bold');
      } else {
        pdf.setFont('courier', 'normal');
      }

      pdf.text(text, pageWidth / 2, yPosition, { align: align === 'center' ? 'center' : 'left', maxWidth: textWidth });
      yPosition += lineHeight;
    });

    yPosition += lineHeight;

    // Footer information
    pdf.setFontSize(10);
    pdf.setFont('courier', 'normal');
    pdf.text(`Issued Date: ${certificate.issueDate || new Date().toLocaleDateString()}`, margin, pageHeight - margin - 15);
    pdf.text(`Instructor: ${certificate.instructorName || 'Instructor Name'}`, margin, pageHeight - margin - 10);
    pdf.text(`Certificate ID: ${certificate.certificateId || 'N/A'}`, margin, pageHeight - margin - 5);

    // Save
    const filename = `Certificate_${certificate.studentName?.replace(/\s+/g, '_') || 'Student'}.pdf`;
    pdf.save(filename);

  } catch (error) {
    console.error('Error creating PDF:', error);
    alert('Error creating PDF. Please try again.');
  }
};

/**
 * Print certificate (browser's print dialog)
 */
export const printCertificate = (certificateRef) => {
  try {
    const printWindow = window.open('', '_blank');
    if (!certificateRef?.innerHTML) {
      alert('Certificate not found for printing');
      return;
    }

    printWindow.document.write(`
      <!DOCTYPE html>
      <html>
        <head>
          <title>Certificate</title>
          <style>
            body {
              margin: 0;
              padding: 0;
              background: white;
            }
            @media print {
              body { margin: 0; }
            }
          </style>
        </head>
        <body>
          ${certificateRef.innerHTML}
          <script>
            window.print();
            window.close();
          </script>
        </body>
      </html>
    `);
    printWindow.document.close();
  } catch (error) {
    console.error('Error printing certificate:', error);
    alert('Error printing certificate. Please try again.');
  }
};

export default {
  downloadCertificateAsPDF,
  generateCertificatePDFSimple,
  printCertificate,
};
